use strict;
use warnings;
use PDF::API2;
use Text::SimpleTable;

# Function to extract text from PDF
sub extract_pdf_text {
    my ($file) = @_;
    my $pdf = PDF::API2->open($file);

    my @texts = ();
    foreach my $page (1 .. $pdf->pages) {
        my $text = $pdf->page($page)->text();
        push @texts, $text;
    }
    $pdf->close();
    return join("\n", @texts);
}

# Function to find specific data in extracted text
